/**
 * PREDICTION MODEL
 * 
 * This schema stores the specific insights generated by the Pulse ML Engine
 * for a given daily log. It includes scores, burnout classification, 
 * persona grouping, and detailed factor analysis.
 */

const mongoose = require('mongoose');

const predictionSchema = new mongoose.Schema({
  userId: {
    type: mongoose.Schema.Types.ObjectId,
    ref: 'User',
    required: [true, 'User ID is required'],
    index: true
  },
  /**
   * logId: Links this prediction to the specific DailyLog entry.
   * There is a strict One-to-One relationship between a Log and a Prediction.
   */
  logId: {
    type: mongoose.Schema.Types.ObjectId,
    ref: 'DailyLog',
    required: [true, 'Log ID is required'],
    unique: true,
    index: true
  },

  // --- SCORE & RISK METRICS ---
  
  productivityScore: {
    type: Number, // Calculated on a scale of 0-100
    required: [true, 'Productivity score is required'],
    min: [0, 'Productivity score minimum is 0'],
    max: [100, 'Productivity score maximum is 100']
  },
  burnoutRisk: {
    type: String, // 'Low', 'Medium', or 'High'
    enum: {
      values: ['Low', 'Medium', 'High'],
      message: 'Invalid burnout risk'
    },
    required: [true, 'Burnout risk is required']
  },
  burnoutConfidence: {
    type: Object, // Map of probabilities for each risk level (e.g., { Low: 0.9, Medium: 0.1 })
    required: [true, 'Burnout confidence scores are required']
  },
  primaryConfidence: {
    type: Number, // The specific confidence score for the predicted 'burnoutRisk'
    required: [true, 'Primary confidence is required'],
    min: 0,
    max: 1
  },

  // --- BEHAVIORAL GROUPING ---
  
  persona: {
    type: String, // Human-readable category (e.g., 'Balanced Optimizer')
    required: [true, 'Persona is required']
  },
  clusterId: {
    type: Number, // Numerical ID of the K-Means cluster
    required: [true, 'Cluster ID is required'],
    index: true
  },
  personaReason: {
    type: String,
    default: "Consistent behavior detected."
  },

  // --- INSIGHTS & EXPLANATIONS ---
  
  topPositiveFactors: {
    type: [String], // Simple list of labels (e.g., ['Sleep Hygiene', 'Hydration'])
    default: []
  },
  topNegativeFactors: {
    type: [String], // e.g., ['Stress Levels', 'Screen Time']
    default: []
  },
  topPositiveFactorsDetailed: {
    type: [Object], // Includes 'label' and 'insight' (the humanized explanation)
    default: []
  },
  topNegativeFactorsDetailed: {
    type: [Object],
    default: []
  },
  factorContributions: {
    type: [Object], // Full raw contribution scores for advanced analytics
    default: []
  },

  // --- PEER BENCHMARKING (Social Comparison) ---
  
  peer_benchmark: {
    sleep_percentile: { type: Number, min: 0, max: 100 },
    productivity_percentile: { type: Number, min: 0, max: 100 },
    focus_percentile: { type: Number, min: 0, max: 100 },
    burnout_percentile: { type: Number, min: 0, max: 100 },
    cluster_size: { type: Number }, // Number of users in this specific behavioral group
    is_available: { type: Boolean, default: false }
  },

  // --- METADATA ---
  
  isEdited: {
    type: Boolean, // True if the log (and thus prediction) was updated today
    default: false
  },
  date: {
    type: Date,
    required: [true, 'Date is required'],
    default: Date.now,
    index: true
  }
}, {
  timestamps: true
});

// Optimized for retrieving historical trends
predictionSchema.index({ userId: 1, date: -1 });

const Prediction = mongoose.model('Prediction', predictionSchema);

module.exports = Prediction;

